module.exports = function(RED) {
    function GoToNode(config) {
        RED.nodes.createNode(this, config);
        var node = this;

        node.name = config.name;
        node.activation = config.activation;
        node.principale = config.principale;
        node.desactivation = config.desactivation;
        node.raz_compteur = config.raz_compteur;
        node.cmd = config.cmd;

        node.on('input', function(msg) {
            node.send(null);
        });
    }
    RED.nodes.registerType("goto", GoToNode);
}
